#!/usr/bin/env bash
# synergy.sh — Synergy 决策助手 for 投行并购.
# Auto-generated by cli_writer.py. Source: synthesis.md Section 2 (Playbook).
set -euo pipefail
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
source "${SCRIPT_DIR}/../lib/common.sh"

INDUSTRY="投行并购"
TOPIC="Synergy"

usage() {
  cat <<EOF
synergy.sh — ${TOPIC} 决策助手 for ${INDUSTRY}

基于 2 条 playbook 规则的交互式决策评估。
你描述情景, 工具帮你判断哪条规则适用, 并给推荐。

USAGE:
  ./synergy.sh             # interactive
  ./synergy.sh --dry-run   # walk through but no file
  ./synergy.sh --json      # JSON to stdout
  ./synergy.sh --explain   # show backing playbook rules + mental models
  ./synergy.sh --help      # this message
EOF
}

explain() {
  cat <<'EOT'
这个决策助手把 Synergy 主题下的 playbook 规则组合成交互树。

基于 2 条规则:
  • 如果 陷入竞价战或对手抬价 → 则 按出价前已设的 walk-away/reservation price 退出，**绝不把全部 synergy 当溢价付*
  • 如果 pitch 用 synergy/accretion 抬价 → 则 把 synergy 独立显式预测进现金流、举证责任归出价方，并记住 accretion ≠ 创造价值

相关心智模型:
  • 三层价格——价值——成交价: 这行的人脑子里永远有三个数在打架——**内在价值** (DCF/现金流基本面) ⇄ **市场价格** (trading comps/情绪与动量) ⇄ **成交价** (含 control premiu
  • 价值创造 = 增长 × (ROIC − 资本成本): 价值只有一种创造方式——**以高于资本成本的回报率投资资本**；ROIC 低于资本成本时增长反而毁价，会计/财务工程/回购/EPS 目标都只是重新分配现金流，不创造价值 (conservation o

来源: synthesis.md Section 2.
EOT
}

DRY_RUN=0; JSON=0
for arg in "$@"; do
  case "$arg" in
    --help|-h) usage; exit 0 ;;
    --explain) explain; exit 0 ;;
    --dry-run) DRY_RUN=1 ;;
    --json) JSON=1 ;;
  esac
done

declare -a RULE_CONDITIONS=(
  "陷入竞价战或对手抬价"
  "pitch 用 synergy/accretion 抬价"
)
declare -a RULE_ACTIONS=(
  "按出价前已设的 walk-away/reservation price 退出，**绝不把全部 synergy 当溢价付**"
  "把 synergy 独立显式预测进现金流、举证责任归出价方，并记住 accretion ≠ 创造价值"
)
declare -a APPLIED_RULES=()

ms_section "${INDUSTRY} · ${TOPIC} 决策评估"
ms_info "本工具基于 ${#RULE_CONDITIONS[@]} 条 playbook 规则评估你的情景。"
echo

ms_prompt "请描述当前情景 (空行结束):"
echo
SITUATION="$(ms_read_multiline)"

for i in "${!RULE_CONDITIONS[@]}"; do
  ms_section "Rule $((i+1))/${#RULE_CONDITIONS[@]}"
  echo "适用情景: ${RULE_CONDITIONS[$i]}"
  echo "推荐做法: ${RULE_ACTIONS[$i]}"
  if ms_confirm "这条规则 fit 你当前情景吗?"; then
    APPLIED_RULES+=("$((i+1))")
    ms_ok "适用 rule $((i+1))"
  fi
done

ms_buffer_append "# ${INDUSTRY} — ${TOPIC} 决策报告"
ms_buffer_append ""
ms_buffer_append "_生成时间: $(date '+%Y-%m-%d %H:%M:%S')_"
ms_buffer_append ""
ms_buffer_append "## 情景"
ms_buffer_append ""
ms_buffer_append "$SITUATION"
ms_buffer_append ""
ms_buffer_append "## 适用规则"
ms_buffer_append ""
if [[ ${#APPLIED_RULES[@]} -eq 0 ]]; then
  ms_buffer_append "(无适用 playbook 规则 — 此情景在已知 OS 之外, 建议回到 SKILL.md 心智模型层重新分析)"
else
  for ridx in "${APPLIED_RULES[@]}"; do
    i=$((ridx-1))
    ms_buffer_append "- **情景**: ${RULE_CONDITIONS[$i]} → **做法**: ${RULE_ACTIONS[$i]}"
  done
fi
ms_buffer_append ""

if [[ $JSON -eq 1 ]]; then
  ms_emit_json \
    "topic" "${TOPIC}" \
    "situation" "${SITUATION}" \
    "applied_rules_count" "${#APPLIED_RULES[@]}"
elif [[ $DRY_RUN -eq 1 ]]; then
  ms_emit_md_stdout
else
  ms_emit_md_file "synergy-decision"
fi
